  return (2*sin(pi*x));
}

draw(graph(func,0,4.2),red);
draw(graph(func,8.8,12),red);
draw((0,0)--(4.5,2/11.8*4.5),blue);
draw((8.8,2/11.8*8.8)--(11.8,2),blue);
draw((0,-2)--(0,2));
draw((0,0)--(12,0));

draw((1,-0.1)--(1,0.1));
draw((2,-0.1)--(2,0.1));
draw((3,-0.1)--(3,0.1));
draw((4,-0.1)--(4,0.1));
