path[] yh(real a, real b, real h, real k, real x0, real x1, bool upper=true, bool lower=true, pen color=black , real ys=1)
{
	real f(real x) { return k + a / b * sqrt(b^2 + (x-h)^2); }
    real g(real x) { return k - a / b * sqrt(b^2 + (x-h)^2); }
    if (upper) { draw(xscale(ys)*graph(f, x0, x1),color,  Arrows); }
    if (lower) { draw(xscale(ys)*graph(g, x0, x1),color,  Arrows); }
    path [] arr = {xscale(ys)*graph(f, x0, x1), xscale(ys)*graph(g, x0, x1)};
    return arr;
}
void xh(real a, real b, real h, real k, real y0, real y1, bool right=true, bool left=true, pen color=black , real ys=1)
{
	path [] arr = yh(a, b, k, h, y0, y1, false, false, ys);
    if (right) draw(reflect((0,0),(1,1))*arr[0],color,  Arrows);
    if (left) draw(reflect((0,0),(1,1))*arr[1],color,  Arrows);
}
void e(real a, real b, real h, real k)
{
	draw(shift((h,k))*scale(a,b)*unitcircle);
}
